package be.schaubroeck.lpb.rkm.rekenmotor.cache;

import be.schaubroeck.lpb.rkm.rekenmotor.cache.CacheContext.Scope;
import be.schaubroeck.lpb.tools.APKPrincipe;
import be.schaubroeck.lpb.tools.criteria.CriteriaBuilder;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.service.APKPrincipeService;
import be.schaubroeck.lpb.tools.util.TimeLogContext;
import be.schaubroeck.temporal.interval.LocalDateInterval;
import lombok.Data;
import org.joda.time.LocalDate;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class CachedApkPrincipeService implements CachedService, APKPrincipeService {

    @Autowired
    private APKPrincipeService apkPrincipeService;

    private static final ThreadLocal<CachedApkPrincipeBuffer> BUFFER = new ThreadLocal<>();

    public CachedApkPrincipeService() {
        super();
        CacheContext.getInstance().registerCachedServices(this, Scope.ADMIN);
    }


    @Override
    public APKPrincipe getByWerkgeversCategorieWerknemersKengetalLooncodeDatum(
            WerkgeversCategorie werkgeversCategorie,
            DmfapplWnkengetal werknemersKengetal, Integer looncode, LocalDate datum) {
        TimeLogContext.getInstance().startTimeLogging("CachedApkPrincipeService.getByWerkgeversCategorieWerknemersKengetalLooncodeDatum");
        CachedApkPrincipeBuffer buffer = CachedApkPrincipeService.getBuffer();
        APKPrincipeKey key = new APKPrincipeKey(werkgeversCategorie, werknemersKengetal, looncode);
        List<APKPrincipe> results = buffer.get(key);
        if (results == null) {
            results = apkPrincipeService.findByWerkgeversCategorieWerknemersKengetalLooncode(werkgeversCategorie, werknemersKengetal, looncode);
            buffer.put(key, results);
        }
        APKPrincipe result = zoekLijst(results, datum);
        TimeLogContext.getInstance().endTimeLogging();
        return result;
    }


    private APKPrincipe zoekLijst(List<APKPrincipe> lijst, LocalDate datum) {
        APKPrincipe result = null;
        for (APKPrincipe constant : lijst) {
            LocalDateInterval periode = new LocalDateInterval(constant.getBeginDatum(), constant.getEindDatum());
            if (periode.contains(datum)) {
                result = constant;
                break;
            }
        }
        return result;
    }

    @Override
    public void clearCache() {
        CachedApkPrincipeService.getBuffer().clear();
    }

    private static class CachedApkPrincipeBuffer {

        private final Map<APKPrincipeKey, List<APKPrincipe>> apkPrincipeBuffer = new HashMap<>();

        public List<APKPrincipe> get(APKPrincipeKey key) {
            return apkPrincipeBuffer.get(key);
        }

        public void put(APKPrincipeKey key, List<APKPrincipe> lijst) {
            apkPrincipeBuffer.put(key, lijst);
        }

        public void clear() {
            apkPrincipeBuffer.clear();
        }
    }

    private static CachedApkPrincipeBuffer getBuffer() {
        CachedApkPrincipeBuffer returnValue = BUFFER.get();
        if (returnValue == null) {
            returnValue = new CachedApkPrincipeBuffer();
            BUFFER.set(returnValue);
        }
        return returnValue;
    }

    @Data
    private static class APKPrincipeKey {

        private final int werkgeversCategorie;
        private final int werknemersKengetal;
        private final int looncode;

        APKPrincipeKey(WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, Integer looncode) {
            this.werkgeversCategorie = werkgeversCategorie.getCode();
            this.werknemersKengetal = werknemersKengetal.getCode();
            this.looncode = looncode;
        }
    }

    //Forwarding naar Standard...Service, we gebruiken hier geen overerving omdat we de @Transcational willen vermijden.

    @Override
    public List<APKPrincipe> findByWerkgeversCategorieWerknemersKengetal(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal) {
        return apkPrincipeService.findByWerkgeversCategorieWerknemersKengetal(werkgeversCategorie, werknemersKengetal);
    }

    @Override
    public List<APKPrincipe> findByWerkgeversCategorieWerknemersKengetalDatum(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, LocalDate datum) {
        return apkPrincipeService.findByWerkgeversCategorieWerknemersKengetalDatum(werkgeversCategorie, werknemersKengetal, datum);
    }

    @Override
    public List<APKPrincipe> findByWerkgeversCategorieWerknemersKengetalLooncode(
            WerkgeversCategorie werkgeversCategorie, DmfapplWnkengetal werknemersKengetal, Integer looncode) {
        return apkPrincipeService.findByWerkgeversCategorieWerknemersKengetalLooncode(werkgeversCategorie, werknemersKengetal, looncode);
    }

    @Override
    public List<APKPrincipe> findAll() {
        return apkPrincipeService.findAll();
    }

    @Override
    public APKPrincipe create(APKPrincipe constant) {
        return apkPrincipeService.create(constant);
    }

    @Override
    public void update(APKPrincipe constant) {
        apkPrincipeService.update(constant);
    }

    @Override
    public void delete(APKPrincipe constant) {
        apkPrincipeService.delete(constant);
    }

    @Override
    public APKPrincipe getById(Integer id) {
        return apkPrincipeService.getById(id);
    }

    @Override
    public APKPrincipe getById(Integer id, String fetchFields) {
        return apkPrincipeService.getById(id, fetchFields);
    }

    @Override
    public APKPrincipe getByCriteria(CriteriaBuilder cb) {
        return apkPrincipeService.getByCriteria(cb);
    }


    @Override
    public List<APKPrincipe> findAll(String fetchFields) {
        return apkPrincipeService.findAll(fetchFields);
    }

    @Override
    public List<APKPrincipe> findByCriteria(CriteriaBuilder cb) {
        return apkPrincipeService.findByCriteria(cb);
    }

    @Override
    public Integer countByCriteria(CriteriaBuilder cb) {
        return apkPrincipeService.countByCriteria(cb);
    }

    @Override
    public Map<Integer, APKPrincipe> cacheByCriteria(CriteriaBuilder cb) {
        return apkPrincipeService.cacheByCriteria(cb);
    }

    @Override
    public APKPrincipe getByCriteriaTemporalFree(CriteriaBuilder cb) {
        return apkPrincipeService.getByCriteriaTemporalFree(cb);
    }

    @Override
    public List<APKPrincipe> findByCriteriaTemporalFree(CriteriaBuilder cb) {
        return apkPrincipeService.findByCriteriaTemporalFree(cb);
    }

}
